from pathlib import Path
import sys
import re

SOURCE = Path(sys.argv[1] if len(sys.argv) > 1 else "games.html")
OUTPUT = Path(sys.argv[2] if len(sys.argv) > 2 else "games-v0.9.0.html")

START = '<!-- NLDG VERSION 0.9.0 SPRINT 2 START -->'
END = '<!-- NLDG VERSION 0.9.0 SPRINT 2 END -->'
BLOCK = '<!-- NLDG VERSION 0.9.0 SPRINT 2 START -->\n<script>\n(() => {\n  "use strict";\n\n  const host = window;\n  const doc = document;\n  const storageKey = "nldg-sprint2-settings";\n  const historyKey = "nldg-tournament-history";\n  const settings = Object.assign(\n    { autoRotate: true },\n    JSON.parse(localStorage.getItem(storageKey) || "{}")\n  );\n  let roundSnapshots = JSON.parse(localStorage.getItem(historyKey) || "[]");\n\n  const $ = id => doc.getElementById(id);\n  const escapeHtml = value => String(value ?? "").replace(/[&<>"\']/g, char => ({\n    "&": "&amp;", "<": "&lt;", ">": "&gt;", \'"\': "&quot;", "\'": "&#039;"\n  }[char]));\n  const teams = () => Array.isArray(host.state?.teams) ? host.state.teams : [];\n  const activeIndex = () => Number(host.state?.activeTeam || 0);\n\n  function rankedTeams() {\n    return teams()\n      .map((team, index) => ({\n        index,\n        name: team.name || `Team ${index + 1}`,\n        score: Number(team.score || 0),\n        color: team.color || "#2f6fed"\n      }))\n      .sort((a, b) => b.score - a.score || a.index - b.index);\n  }\n\n  function injectStyles() {\n    const style = doc.createElement("style");\n    style.textContent = `\n      .sprint2-controls{display:flex;gap:8px;align-items:center;flex-wrap:wrap}\n      .sprint2-toggle{display:flex;align-items:center;gap:7px;padding:10px 12px;border-radius:12px;background:#12295e;font-weight:900}\n      .sprint2-toggle input{width:20px;height:20px}\n      .live-rankings{position:fixed;right:14px;bottom:14px;z-index:140;width:min(330px,calc(100vw - 28px));max-height:48vh;overflow:auto;padding:12px;border:2px solid rgba(255,211,78,.48);border-radius:18px;background:rgba(3,10,30,.96);box-shadow:0 20px 60px rgba(0,0,0,.45)}\n      .live-rankings.hidden{display:none!important}\n      .rankings-head{display:flex;justify-content:space-between;align-items:center;gap:10px;margin-bottom:8px}\n      .rankings-head strong{color:#ffd34e;font-size:18px}\n      .ranking-row{display:grid;grid-template-columns:34px 1fr auto;align-items:center;gap:8px;padding:9px 7px;border-left:5px solid var(--team-color);border-radius:9px;background:rgba(255,255,255,.05);margin-top:7px}\n      .ranking-row.active{outline:2px solid #ffd34e}\n      .ranking-score{color:#ffd34e;font-weight:1000}\n      .summary-table{width:100%;border-collapse:separate;border-spacing:0 8px}\n      .summary-table td{padding:12px;background:rgba(255,255,255,.06)}\n      .summary-table td:first-child{border-radius:10px 0 0 10px}\n      .summary-table td:last-child{border-radius:0 10px 10px 0;color:#ffd34e;font-weight:1000;text-align:right}\n      .round-history{max-height:190px;overflow:auto;text-align:left;width:100%;padding:8px 12px;border-radius:12px;background:rgba(255,255,255,.04)}\n      @media(max-width:800px){.live-rankings{position:static;width:100%;max-height:none;margin:10px 0}.sprint2-controls{justify-content:center}}\n      body.playing .live-rankings{bottom:max(12px,env(safe-area-inset-bottom))}\n    `;\n    doc.head.appendChild(style);\n  }\n\n  function injectControls() {\n    const topActions = doc.querySelector(".top-actions");\n    if (topActions && !$("sprint2Controls")) {\n      const wrap = doc.createElement("div");\n      wrap.id = "sprint2Controls";\n      wrap.className = "sprint2-controls";\n      wrap.innerHTML = `\n        <button type="button" class="btn gold" id="nextTeamBtn">Next Team ➜</button>\n        <label class="sprint2-toggle"><input type="checkbox" id="autoRotateTeams"> Auto Rotate</label>\n        <button type="button" class="btn" id="toggleRankingsBtn">📊 Rankings</button>\n        <button type="button" class="btn" id="tournamentSummaryBtn">🏆 Summary</button>`;\n      topActions.prepend(wrap);\n    }\n\n    if (!$("liveRankings")) {\n      const panel = doc.createElement("aside");\n      panel.id = "liveRankings";\n      panel.className = "live-rankings";\n      panel.setAttribute("aria-live", "polite");\n      doc.body.appendChild(panel);\n    }\n\n    if (!$("sprint2SummaryOverlay")) {\n      const overlay = doc.createElement("div");\n      overlay.id = "sprint2SummaryOverlay";\n      overlay.className = "overlay hidden";\n      overlay.innerHTML = `\n        <div class="overlay-card center">\n          <div class="winner-icon">🏆</div>\n          <h2>Tournament Summary</h2>\n          <div id="sprint2SummaryContent"></div>\n          <div class="host-controls">\n            <button type="button" class="btn gold xl" id="closeSprint2Summary">Continue Playing</button>\n            <button type="button" class="btn danger" id="clearSprint2History">Clear History</button>\n          </div>\n        </div>`;\n      doc.body.appendChild(overlay);\n    }\n\n    $("autoRotateTeams").checked = settings.autoRotate;\n    $("nextTeamBtn").onclick = () => rotateTeam(true);\n    $("autoRotateTeams").onchange = event => {\n      settings.autoRotate = event.target.checked;\n      localStorage.setItem(storageKey, JSON.stringify(settings));\n      renderRankings();\n    };\n    $("toggleRankingsBtn").onclick = () => $("liveRankings").classList.toggle("hidden");\n    $("tournamentSummaryBtn").onclick = showSummary;\n    $("closeSprint2Summary").onclick = () => $("sprint2SummaryOverlay").classList.add("hidden");\n    $("clearSprint2History").onclick = () => {\n      roundSnapshots = [];\n      localStorage.removeItem(historyKey);\n      showSummary();\n    };\n  }\n\n  function rotateTeam(force = false) {\n    if (!force && !settings.autoRotate) return;\n    const list = teams();\n    if (list.length < 2) return;\n    const next = (activeIndex() + 1) % list.length;\n    if (typeof host.setActiveTeam === "function") host.setActiveTeam(next);\n    else if (host.state) host.state.activeTeam = next;\n    renderRankings();\n  }\n\n  function renderRankings() {\n    const panel = $("liveRankings");\n    if (!panel) return;\n    const ranking = rankedTeams();\n    panel.innerHTML =\n      `<div class="rankings-head"><strong>Live Rankings</strong><span>${settings.autoRotate ? "Auto rotation on" : "Manual rotation"}</span></div>` +\n      ranking.map((team, position) => `\n        <div class="ranking-row ${team.index === activeIndex() ? "active" : ""}" style="--team-color:${team.color}">\n          <strong>${position + 1}</strong>\n          <span>${escapeHtml(team.name)}</span>\n          <span class="ranking-score">${team.score}</span>\n        </div>`).join("");\n  }\n\n  function captureRound() {\n    const tournament = host.state?.tournament;\n    roundSnapshots.push({\n      at: new Date().toISOString(),\n      round: tournament?.round || roundSnapshots.length + 1,\n      scores: rankedTeams().map(team => ({ name: team.name, score: team.score }))\n    });\n    roundSnapshots = roundSnapshots.slice(-20);\n    localStorage.setItem(historyKey, JSON.stringify(roundSnapshots));\n    renderRankings();\n  }\n\n  function showSummary() {\n    const ranking = rankedTeams();\n    const content = $("sprint2SummaryContent");\n    const tournament = host.state?.tournament;\n    content.innerHTML = `\n      <p>${tournament?.active ? `Round ${tournament.round} of ${tournament.total}` : "Current standings"}</p>\n      <table class="summary-table"><tbody>\n        ${ranking.map((team, position) => `<tr><td>${position + 1}. ${escapeHtml(team.name)}</td><td>${team.score} points</td></tr>`).join("")}\n      </tbody></table>\n      <div class="round-history">\n        <strong>Round History</strong>\n        ${roundSnapshots.length\n          ? roundSnapshots.map(snapshot => `<p>Round ${snapshot.round}: ${snapshot.scores.map(score => `${escapeHtml(score.name)} ${score.score}`).join(" • ")}</p>`).join("")\n          : "<p>No completed rounds recorded yet.</p>"}\n      </div>`;\n    $("sprint2SummaryOverlay").classList.remove("hidden");\n  }\n\n  function patchScoreUpdates() {\n    if (typeof host.renderScoreboard === "function") {\n      const original = host.renderScoreboard;\n      host.renderScoreboard = function (...args) {\n        const result = original.apply(this, args);\n        renderRankings();\n        return result;\n      };\n    }\n\n    if (typeof host.awardJeopardy === "function") {\n      const originalAward = host.awardJeopardy;\n      host.awardJeopardy = function (team) {\n        const result = originalAward.call(this, team);\n        if (settings.autoRotate && Number(team) === activeIndex()) rotateTeam();\n        renderRankings();\n        return result;\n      };\n      if (typeof host.renderJeopardyAwardButtons === "function") {\n        host.renderJeopardyAwardButtons();\n      }\n    }\n\n    if (typeof host.nextQuiz === "function") {\n      const originalNext = host.nextQuiz;\n      host.nextQuiz = function () {\n        if (!settings.autoRotate && host.state) {\n          const current = activeIndex();\n          const originalSet = host.setActiveTeam;\n          host.setActiveTeam = () => {};\n          try {\n            return originalNext.call(this);\n          } finally {\n            host.setActiveTeam = originalSet;\n            host.state.activeTeam = current;\n            if (originalSet) originalSet(current);\n            renderRankings();\n          }\n        }\n        const result = originalNext.call(this);\n        renderRankings();\n        return result;\n      };\n      const nextButton = $("quizNextBtn");\n      if (nextButton) nextButton.onclick = host.nextQuiz;\n    }\n  }\n\n  function install() {\n    if (!host.state || typeof host.showView !== "function") {\n      setTimeout(install, 100);\n      return;\n    }\n\n    injectStyles();\n    injectControls();\n    patchScoreUpdates();\n    renderRankings();\n\n    doc.addEventListener("nldg:round-complete", captureRound);\n    doc.addEventListener("keydown", event => {\n      const tag = (doc.activeElement?.tagName || "").toLowerCase();\n      if (["input", "select", "textarea"].includes(tag)) return;\n      if (event.key.toLowerCase() === "n") rotateTeam(true);\n      if (event.key.toLowerCase() === "r" && event.shiftKey) showSummary();\n    });\n  }\n\n  install();\n})();\n</script>\n<!-- NLDG VERSION 0.9.0 SPRINT 2 END -->'

if not SOURCE.exists():
    raise SystemExit(f"Could not find {SOURCE}")

text = SOURCE.read_text(encoding="utf-8")

# Remove the earlier external add-on, if it was installed.
text = re.sub(r'\s*<script\s+src=["\']sprint2\.js["\']\s*></script>\s*', "\n", text, flags=re.I)

# Replace an earlier native Sprint 2 block or insert a fresh one.
pattern = re.compile(re.escape(START) + r".*?" + re.escape(END), re.S)
if pattern.search(text):
    text = pattern.sub(BLOCK, text)
elif "</body>" in text:
    text = text.replace("</body>", BLOCK + "\n</body>", 1)
else:
    raise SystemExit("Could not find </body> in games.html")

# Update visible version references where safe.
text = text.replace("Version 0.9 • Sprint 1", "Version 0.9.0 • Sprint 2")
text = text.replace("VERSION 0.8.1", "VERSION 0.9.0")

OUTPUT.write_text(text, encoding="utf-8")

# Sanity checks.
built = OUTPUT.read_text(encoding="utf-8")
checks = {
    "single inline Sprint 2 block": built.count(START) == 1 and built.count(END) == 1,
    "no external sprint2.js dependency": 'src="sprint2.js"' not in built and "src='sprint2.js'" not in built,
    "has Next Team": "Next Team" in built,
    "has Live Rankings": "Live Rankings" in built,
    "has Tournament Summary": "Tournament Summary" in built,
    "retains closing HTML": "</body>" in built and "</html>" in built,
}
failed = [name for name, passed in checks.items() if not passed]
if failed:
    OUTPUT.unlink(missing_ok=True)
    raise SystemExit("Build failed checks: " + ", ".join(failed))

print(f"Created {OUTPUT}")
for name in checks:
    print(f"PASS: {name}")
